using Store;

namespace Store.Tests;

[TestClass]
public sealed class ShoppingCartTests
{
    private ShoppingCart _cart = null!;

    [TestInitialize]
    public void Setup() => _cart = new ShoppingCart();

    // ── AddItem ──────────────────────────────────────────────

    [TestMethod]
    public void AddItem_SingleItem_AppearsInCart()
    {
        _cart.AddItem("SKU-1", 2, 9.99m);

        Assert.AreEqual(1, _cart.Items.Count);
        Assert.AreEqual(2, _cart.Items["SKU-1"].Quantity);
        Assert.AreEqual(9.99m, _cart.Items["SKU-1"].Price);
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_CombinesQuantity()
    {
        _cart.AddItem("SKU-1", 1, 5.00m);
        _cart.AddItem("SKU-1", 3, 5.00m);

        Assert.AreEqual(1, _cart.Items.Count);
        Assert.AreEqual(4, _cart.Items["SKU-1"].Quantity);
    }

    [TestMethod]
    public void AddItem_MultipleSkus_AllTracked()
    {
        _cart.AddItem("A", 1, 1.00m);
        _cart.AddItem("B", 2, 2.00m);

        Assert.AreEqual(2, _cart.Items.Count);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void AddItem_InvalidSku_Throws(string? sku)
        => Assert.ThrowsException<ArgumentException>(() => _cart.AddItem(sku!, 1, 1.00m));

    [TestMethod]
    [DataRow(0)]
    [DataRow(-1)]
    public void AddItem_InvalidQuantity_Throws(int qty)
        => Assert.ThrowsException<ArgumentOutOfRangeException>(() => _cart.AddItem("SKU", qty, 1.00m));

    [TestMethod]
    public void AddItem_NegativePrice_Throws()
        => Assert.ThrowsException<ArgumentOutOfRangeException>(() => _cart.AddItem("SKU", 1, -1.00m));

    [TestMethod]
    public void AddItem_ZeroPrice_Allowed()
    {
        _cart.AddItem("FREE", 1, 0m);
        Assert.AreEqual(0m, _cart.Items["FREE"].Price);
    }

    // ── RemoveItem ───────────────────────────────────────────

    [TestMethod]
    public void RemoveItem_ExistingItem_RemovesFromCart()
    {
        _cart.AddItem("SKU-1", 1, 10.00m);
        _cart.RemoveItem("SKU-1");

        Assert.AreEqual(0, _cart.Items.Count);
    }

    [TestMethod]
    public void RemoveItem_NonExistentSku_ThrowsKeyNotFound()
        => Assert.ThrowsException<KeyNotFoundException>(() => _cart.RemoveItem("MISSING"));

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    public void RemoveItem_InvalidSku_Throws(string? sku)
        => Assert.ThrowsException<ArgumentException>(() => _cart.RemoveItem(sku!));

    // ── CalculateTotal ───────────────────────────────────────

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
        => Assert.AreEqual(0m, _cart.CalculateTotal());

    [TestMethod]
    public void CalculateTotal_SingleItem_ReturnsCorrectTotal()
    {
        _cart.AddItem("SKU-1", 3, 10.00m);
        Assert.AreEqual(30.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_MultipleItems_SumsAll()
    {
        _cart.AddItem("A", 2, 5.00m);   // 10
        _cart.AddItem("B", 1, 15.00m);  // 15

        Assert.AreEqual(25.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_AfterRemoval_ExcludesRemovedItem()
    {
        _cart.AddItem("A", 1, 10.00m);
        _cart.AddItem("B", 1, 20.00m);
        _cart.RemoveItem("A");

        Assert.AreEqual(20.00m, _cart.CalculateTotal());
    }

    // ── ApplyCoupon ──────────────────────────────────────────

    [TestMethod]
    [DataRow("SAVE10", 10)]
    [DataRow("SAVE20", 20)]
    [DataRow("HALF",   50)]
    public void ApplyCoupon_ValidCode_AppliesDiscount(string code, int pct)
    {
        _cart.AddItem("SKU-1", 1, 100.00m);
        _cart.ApplyCoupon(code);

        Assert.AreEqual(100.00m - pct, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_CaseInsensitive()
    {
        _cart.AddItem("SKU-1", 1, 100.00m);
        _cart.ApplyCoupon("save10");

        Assert.AreEqual(90.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_SetsAppliedCouponProperty()
    {
        _cart.ApplyCoupon("SAVE10");
        Assert.AreEqual("SAVE10", _cart.AppliedCoupon);
    }

    [TestMethod]
    public void ApplyCoupon_UnknownCode_Throws()
        => Assert.ThrowsException<ArgumentException>(() => _cart.ApplyCoupon("BOGUS"));

    [TestMethod]
    public void ApplyCoupon_Twice_ThrowsInvalidOperation()
    {
        _cart.ApplyCoupon("SAVE10");
        Assert.ThrowsException<InvalidOperationException>(() => _cart.ApplyCoupon("SAVE20"));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    public void ApplyCoupon_InvalidCode_Throws(string? code)
        => Assert.ThrowsException<ArgumentException>(() => _cart.ApplyCoupon(code!));

    // ── Integration-style ────────────────────────────────────

    [TestMethod]
    public void FullWorkflow_AddItemsApplyCouponCalculateTotal()
    {
        _cart.AddItem("A", 2, 25.00m);   // 50
        _cart.AddItem("B", 1, 50.00m);   // 50
        _cart.ApplyCoupon("SAVE20");      // 20% off

        Assert.AreEqual(80.00m, _cart.CalculateTotal());
    }
}

